function l(r){return Math.floor(r/8)}function y(r){return 1<<r%8}class x{constructor(e){this.size=e,this._byteArray=new Uint8Array(Math.ceil(this.size/8))}get(e){if(e>=this.size)throw new RangeError("Bit index out of range");const n=l(e),o=y(e);return(this._byteArray[n]&o)!==0}set(e,n){if(e>=this.size)throw new RangeError("Bit index out of range");const o=l(e),s=y(e);n?this._byteArray[o]|=s:this._byteArray[o]&=~s}}function b(r){const e=[],n=r.length/3;for(let t=0;t<n;t++)e.push([r[t*3],r[t*3+1],r[t*3+2]]);const o=new Map;for(let t=0;t<e.length;t++){const a=e[t];for(const c of a){let f=o.get(c);f||o.set(c,f=[]),f.push(t)}}const s=new x(n),h=[],p=t=>{const a=[t];for(;a.length>0;){const c=a.pop();if(!s.get(c)){s.set(c,!0),h.push(e[c]);for(const f of e[c]){const u=o.get(f);if(!u)return;for(const g of u)s.get(g)||a.push(g)}}}};for(let t=0;t<n;t++)s.get(t)||p(t);let i=0;for(const t of h)r[i++]=t[0],r[i++]=t[1],r[i++]=t[2]}export{b as OptimizeIndices};
